  const wordListB64 = "";

const wordList = JSON.parse(atob(wordListB64));

const sounds = {
  correct: new Audio('./sounds/correct.mp3'),
  wrong: new Audio('./sounds/error.mp3'),
  win: new Audio('./sounds/win.mp3'),
  lose: new Audio('./sounds/lost.wav'),
  click: new Audio('./sounds/click.wav'),
  play: new Audio('./sounds/start.mp3')
};

Object.values(sounds).forEach(s => { if (s) { s.load(); s.volume = 0.3; } });

let soundEnabled = true;
let animationFrameId;
let timerInterval;
let timeLeft = 30;
let selectedWord = "";
let displayedWord = [];
let wrongGuesses = 0;
const maxGuesses = 6;
let currentDifficulty = "easy";
let currentCategory = "random";
let currentRound = 1;
let maxRounds = 5;
let hintsRemaining = 3;
let maxHints = 3;
let totalWrong = 0;
let totalCorrect = 0;
let ranking = [];
let isGameActive = true;
let isTimerRunning = false;
let usedWords = [];

const wordDisplay = document.getElementById("wordDisplay");
const keyboard = document.getElementById("keyboard");
const wrongDisplay = document.getElementById("wrongGuesses");
const message = document.getElementById("message");
const restartBtn = document.getElementById("restartBtn");
const hintBtn = document.getElementById("hintBtn");
const hintCount = document.getElementById("hintCount");
const hintText = document.getElementById("hintText");
const progressFill = document.getElementById("progressFill");
const progressText = document.getElementById("progressText");
const wordCounter = document.getElementById("wordCounter");
const hearts = document.querySelectorAll(".heart");
const rankingList = document.getElementById("rankingList");
const fireCanvas = document.getElementById("fireCanvas");
const fireBackground = document.getElementById("fireBackground");
const timerDisplay = document.getElementById("timerDisplay");
const appContainer = document.getElementById("appContainer");
const muteBtn = document.getElementById("muteBtn");
const homeBtn = document.getElementById("homeBtn");
const rulesHeaderBtn = document.getElementById("rulesHeaderBtn");
const rulesCloseBtn = document.getElementById("rulesCloseBtn");
const rulesModal = document.getElementById("rulesModal");

const partIds = {
  head: document.getElementById("headPart"),
  body: document.getElementById("bodyPart"),
  armLeft: document.getElementById("armLeftPart"),
  armRight: document.getElementById("armRightPart"),
  legLeft: document.getElementById("legLeftPart"),
  legRight: document.getElementById("legRightPart")
};
const partOrder = ['head', 'body', 'armLeft', 'armRight', 'legLeft', 'legRight'];

const difficultySettings = {
  easy: { minLen: 4, maxLen: 6, maxHints: 3, rounds: 10, timeLimit: 0 },
  medium: { minLen: 6, maxLen: 9, maxHints: 2, rounds: 8, timeLimit: 0 },
  hard: { minLen: 9, maxLen: 14, maxHints: 1, rounds: 6, timeLimit: 30 }
};

function loadRanking() {
  try { const data = localStorage.getItem('forca_ranking'); if (data) ranking = JSON.parse(data); } catch {}
}

function saveRanking() {
  try { localStorage.setItem('forca_ranking', JSON.stringify(ranking)); } catch {}
}

function addRankingEntry(score, errors) {
  loadRanking();
  ranking.push({ score, errors, date: new Date().toLocaleDateString() });
  ranking.sort((a, b) => b.score - a.score || a.errors - b.errors);
  if (ranking.length > 10) ranking = ranking.slice(0, 10);
  saveRanking();
  renderRanking();
}

function renderRanking() {
  if (!ranking.length) {
    rankingList.innerHTML = '<div class="rank-empty">Nenhuma partida ainda</div>';
    return;
  }
  rankingList.innerHTML = ranking.map((item, i) =>
    `<div class="rank-item">
      <span class="pos">#${i+1}</span>
      <span>${item.score} acertos</span>
      <span class="score">${item.errors} erros</span>
      <span class="date">${item.date}</span>
    </div>`
  ).join('');
}

function getWordByCategory() {
  let filtered = wordList;
  if (currentCategory !== 'random') {
    filtered = wordList.filter(w => w.category === currentCategory);
  }
  const settings = difficultySettings[currentDifficulty];
  filtered = filtered.filter(w => {
    const clean = normalizeWord(w.word);
    return clean.length >= settings.minLen && clean.length <= settings.maxLen;
  });
  if (!filtered.length) return wordList[Math.floor(Math.random() * wordList.length)];
  return filtered[Math.floor(Math.random() * filtered.length)];
}

function getRandomWord() {
  const selected = getWordByCategory();
  const word = selected.word.toLowerCase();
  
  let attempts = 0;
  let newWord = word;
  while (usedWords.includes(newWord) && attempts < 10) {
    const newSelected = getWordByCategory();
    newWord = newSelected.word.toLowerCase();
    attempts++;
  }
  
  usedWords.push(newWord);
  return {
    word: newWord,
    hint: `DEFINIÇÃO: ${selected.description}`
  };
}

function normalizeWord(word) {
  return word.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z]/g, "");
}

function playSound(name) {
  if (!soundEnabled) return;
  const s = sounds[name];
  if (s) { s.currentTime = 0; s.play().catch(() => {}); }
}

function stopLoseSound() {
  sounds.lose.pause();
  sounds.lose.currentTime = 0;
}

function stopAllSounds() {
  Object.values(sounds).forEach(s => { if (s) { s.pause(); s.currentTime = 0; } });
}

function toggleMute() {
  soundEnabled = !soundEnabled;
  if (!soundEnabled) stopAllSounds();
  muteBtn.innerHTML = soundEnabled
    ? '<svg viewBox="0 0 24 24"><path d="M3 9v6h4l5 5V4L7 9H3z"/><path d="M16.5 12c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02z"/><path d="M19.5 12c0-3.35-1.98-6.22-4.5-7.68v1.5c2.04 1.04 3.5 3.14 3.5 5.18s-1.46 4.14-3.5 5.18v1.5c2.52-1.46 4.5-4.33 4.5-7.68z"/></svg>'
    : '<svg viewBox="0 0 24 24"><path d="M16.5 12c0-1.77-1.02-3.29-2.5-4.03v2.21l2.45 2.45c.03-.2.05-.41.05-.63zm2.5 0c0 .94-.2 1.82-.54 2.64l1.51 1.51C20.63 14.91 21 13.5 21 12c0-4.28-2.99-7.86-7-8.77v2.06c2.89.86 5 3.54 5 6.71zM4.27 3L3 4.27 7.73 9H3v6h4l5 5v-6.73l4.25 4.25c-.67.52-1.42.93-2.25 1.18v2.06c1.38-.31 2.63-.95 3.69-1.81L19.73 21 21 19.73l-9-9L4.27 3zM12 4L9.91 6.09 12 8.18V4z"/></svg>';
}

function goHome() {
  stopAllSounds();
  stopTimer();
  if (animationFrameId) cancelAnimationFrame(animationFrameId);
  window.location.href = 'HomeScreen.html';
}

function initFireEffect(forceActive) {
  if (forceActive) {
    fireBackground.classList.add('active');
  } else {
    fireBackground.classList.remove('active');
    return;
  }
  
  const canvas = fireCanvas;
  const ctx = canvas.getContext('2d');
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
  const fw = 100, fh = 100;
  const ps = Math.max(5, Math.floor(canvas.width / fw));
  const fp = new Array(fw * fh).fill(0);

  function update() {
    for (let x = 0; x < fw; x++) {
      for (let y = 1; y < fh; y++) {
        const i = y * fw + x;
        const ny = Math.max(0, y - Math.floor(Math.random() * 3));
        const ni = ny * fw + x;
        fp[ni] = Math.max(0, fp[i] - Math.random() * 0.2);
      }
    }
    for (let x = 0; x < fw; x++) {
      const i = (fh - 1) * fw + x;
      fp[i] = Math.random() > 0.3 ? 1 : 0;
    }
    for (let x = 1; x < fw - 1; x++) {
      for (let y = 0; y < fh; y++) {
        const i = y * fw + x;
        if (fp[i] > 0.1) {
          const s = Math.random() * 0.2;
          fp[i - 1] = Math.min(1, fp[i - 1] + s);
          fp[i + 1] = Math.min(1, fp[i + 1] + s);
        }
      }
    }
  }

  function render() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    for (let x = 0; x < fw; x++) {
      for (let y = 0; y < fh; y++) {
        const i = y * fw + x;
        const inten = fp[i];
        if (inten > 0) {
          let r, g, b;
          if (inten > 0.8) { r = 255; g = 255; b = 255 * (inten - 0.8) * 5; }
          else if (inten > 0.6) { r = 255; g = 255 * (inten - 0.6) * 5; b = 0; }
          else if (inten > 0.3) { r = 255; g = 165 * (inten - 0.3) * 3.33; b = 0; }
          else { r = 255 * inten * 3.33; g = 0; b = 0; }
          ctx.fillStyle = `rgba(${Math.floor(r)},${Math.floor(g)},${Math.floor(b)},${inten})`;
          ctx.fillRect(x * ps, canvas.height - (y * ps), ps, ps);
        }
      }
    }
  }

  function animate() {
    update();
    render();
    animationFrameId = requestAnimationFrame(animate);
  }
  animate();
}

function startTimer() {
  const settings = difficultySettings[currentDifficulty];
  if (settings.timeLimit === 0) {
    timerDisplay.classList.remove('active', 'warning');
    return;
  }

  timeLeft = settings.timeLimit;
  timerDisplay.textContent = `⏱ ${timeLeft}s`;
  timerDisplay.classList.add('active');
  isTimerRunning = true;

  clearInterval(timerInterval);
  timerInterval = setInterval(() => {
    timeLeft--;
    timerDisplay.textContent = `⏱ ${timeLeft}s`;

    if (timeLeft <= 5) {
      timerDisplay.classList.add('warning');
    }

    if (timeLeft <= 0) {
      clearInterval(timerInterval);
      isTimerRunning = false;
      timerDisplay.classList.remove('active', 'warning');

      if (isGameActive) {
        totalWrong++;
        playSound("lose");
        message.innerHTML = `⏱ TEMPO ESGOTADO! A PALAVRA ERA "${selectedWord.toUpperCase()}"`;
        message.className = "message show error timer";
        isGameActive = false;

        partOrder.forEach(id => {
          const p = partIds[id];
          if (p) p.classList.add("dead");
        });

        document.querySelectorAll(".key-btn").forEach(b => b.disabled = true);

        if (currentRound >= maxRounds) {
          setTimeout(() => {
            message.textContent = `FIM DE JOGO! ${totalCorrect} ACERTOS EM ${maxRounds} RODADAS!`;
            message.className = "message show success";
            addRankingEntry(totalCorrect, totalWrong);
            restartBtn.classList.add("show");
          }, 1500);
        } else {
          setTimeout(() => {
            currentRound++;
            initGame();
          }, 2000);
        }
      }
    }
  }, 1000);
}

function stopTimer() {
  clearInterval(timerInterval);
  isTimerRunning = false;
  timerDisplay.classList.remove('active', 'warning');
}

function createConfetti() {
  const container = document.createElement('div');
  container.className = 'confetti-container';
  document.body.appendChild(container);

  const colors = ['#ff2a6d', '#05d9e8', '#00ff9d', '#f9f002', '#d300c5', '#ff6b35', '#ffcc00', '#ff0040'];

  for (let i = 0; i < 120; i++) {
    const piece = document.createElement('div');
    piece.className = 'confetti-piece';
    const size = Math.random() * 8 + 4;
    const left = Math.random() * 100;
    const duration = Math.random() * 2 + 2;
    const delay = Math.random() * 1.5;
    const color = colors[Math.floor(Math.random() * colors.length)];
    const rotate = Math.random() * 360;
    const shape = Math.random() > 0.5 ? '50%' : '2px';

    piece.style.cssText = `
      left: ${left}%;
      width: ${size}px;
      height: ${size * (Math.random() * 2 + 0.5)}px;
      background: ${color};
      border-radius: ${shape};
      animation-duration: ${duration}s;
      animation-delay: ${delay}s;
      transform: rotate(${rotate}deg);
      box-shadow: 0 0 10px ${color};
    `;

    container.appendChild(piece);
  }

  setTimeout(() => {
    container.remove();
  }, 5000);
}

function shakeScreen() {
  appContainer.classList.add('shake-screen');
  setTimeout(() => {
    appContainer.classList.remove('shake-screen');
  }, 500);
}

function initGame() {
  stopLoseSound();
  stopTimer();
  if (animationFrameId) cancelAnimationFrame(animationFrameId);
  isGameActive = true;

  const badge = document.getElementById('categoryBadge');
  const catNames = {
    'random': 'Aleatório',
    'animais': 'Animais',
    'paises': 'Países',
    'tecnologia': 'Tecnologia',
    'cinema': 'Cinema',
    'musica': 'Música'
  };
  badge.textContent = `Categoria: ${catNames[currentCategory] || currentCategory}`;
  
  updateDifficultyBadge();

  const { word, hint } = getRandomWord();
  selectedWord = normalizeWord(word);
  displayedWord = Array(selectedWord.length).fill("_");
  wrongGuesses = 0;

  const settings = difficultySettings[currentDifficulty];
  maxHints = settings.maxHints;
  hintsRemaining = maxHints;

  renderWord();
  updateProgress();
  wrongDisplay.textContent = wrongGuesses;
  wordCounter.textContent = currentRound;
  message.textContent = "";
  message.className = "message";
  restartBtn.classList.remove("show");
  hintBtn.disabled = false;
  hintCount.textContent = hintsRemaining;
  hintBtn.style.opacity = "1";

  hintText.textContent = hint;

  partOrder.forEach(id => {
    const p = partIds[id];
    if (p) { p.classList.remove("visible", "dead"); }
  });

  hearts.forEach(h => {
    h.classList.remove("lost");
    h.style.opacity = "1";
  });

  keyboard.innerHTML = "";
  for (let i = 65; i <= 90; i++) {
    const letter = String.fromCharCode(i).toLowerCase();
    const btn = document.createElement("button");
    btn.className = "key-btn";
    btn.textContent = letter;
    btn.dataset.letter = letter;
    btn.addEventListener("click", () => handleGuess(letter, btn));
    keyboard.appendChild(btn);
  }

  if (currentDifficulty === 'hard') {
    initFireEffect(true);
  } else {
    initFireEffect(false);
  }

  if (settings.timeLimit > 0) {
    setTimeout(startTimer, 300);
  }
}

function renderWord() {
  wordDisplay.innerHTML = displayedWord.map(l =>
    `<span class="letter ${l !== '_' ? 'revealed' : ''}">${l === '_' ? '&nbsp;' : l}</span>`
  ).join('');
}

function updateProgress() {
  const total = selectedWord.length;
  const found = displayedWord.filter(l => l !== '_').length;
  const pct = total > 0 ? Math.round((found / total) * 100) : 0;
  progressFill.style.width = `${pct}%`;
  progressText.textContent = `${pct}%`;
}

function useHint() {
  if (hintsRemaining <= 0 || !isGameActive) {
    message.textContent = "SEM DICAS RESTANTES!";
    message.className = "message show error";
    setTimeout(() => { message.className = "message"; }, 1500);
    return;
  }

  const hidden = displayedWord.map((l, i) => l === '_' ? i : -1).filter(i => i >= 0);
  if (!hidden.length) {
    message.textContent = "TODAS AS LETRAS JÁ FORAM REVELADAS!";
    message.className = "message show info";
    setTimeout(() => { message.className = "message"; }, 1500);
    return;
  }

  const randomIndex = hidden[Math.floor(Math.random() * hidden.length)];
  const letter = selectedWord[randomIndex];

  let revealed = false;
  for (let i = 0; i < selectedWord.length; i++) {
    if (selectedWord[i] === letter && displayedWord[i] === '_') {
      displayedWord[i] = letter;
      revealed = true;
    }
  }

  if (revealed) {
    hintsRemaining--;
    hintCount.textContent = hintsRemaining;
    renderWord();
    updateProgress();
    playSound("correct");

    const btn = document.querySelector(`.key-btn[data-letter="${letter}"]`);
    if (btn && !btn.classList.contains('correct')) {
      btn.classList.add('correct');
      btn.disabled = true;
    }

    message.textContent = `LETRA "${letter.toUpperCase()}" REVELADA!`;
    message.className = "message show info";
    setTimeout(() => { message.className = "message"; }, 1200);
  }

  if (hintsRemaining <= 0) {
    hintBtn.disabled = true;
    hintBtn.style.opacity = "0.3";
  }

  checkGameStatus();
}

function handleGuess(letter, btn) {
  if (!isGameActive) return;
  playSound("click");
  btn.disabled = true;

  if (selectedWord.includes(letter)) {
    playSound("correct");
    btn.classList.add("correct");
    for (let i = 0; i < selectedWord.length; i++) {
      if (selectedWord[i] === letter) displayedWord[i] = letter;
    }
    renderWord();
    updateProgress();
  } else {
    playSound("wrong");
    wrongGuesses++;
    wrongDisplay.textContent = wrongGuesses;
    btn.classList.add("wrong");

    if (wrongGuesses <= partOrder.length) {
      const id = partOrder[wrongGuesses - 1];
      const p = partIds[id];
      if (p) p.classList.add("visible");
    }

    if (wrongGuesses <= hearts.length) {
      hearts[hearts.length - wrongGuesses].classList.add("lost");
    }
  }

  checkGameStatus();
}

function checkGameStatus() {
  if (!isGameActive) return;

  if (!displayedWord.includes("_")) {
    totalCorrect++;
    playSound("win");
    stopTimer();
    message.textContent = "VOCÊ VENCEU!";
    message.className = "message show success";
    isGameActive = false;
    createConfetti();

    if (currentRound >= maxRounds) {
      setTimeout(() => {
        message.textContent = `FIM DE JOGO! ${totalCorrect} ACERTOS EM ${maxRounds} RODADAS!`;
        message.className = "message show success";
        addRankingEntry(totalCorrect, totalWrong);
        endGame();
        createConfetti();
      }, 1000);
    } else {
      setTimeout(() => {
        currentRound++;
        initGame();
      }, 1500);
    }
    return;
  }

  if (wrongGuesses >= maxGuesses) {
    totalWrong++;
    playSound("lose");
    stopTimer();
    message.innerHTML = `VOCÊ PERDEU! A PALAVRA ERA "${selectedWord.toUpperCase()}"`;
    message.className = "message show error";
    isGameActive = false;
    shakeScreen();

    partOrder.forEach(id => {
      const p = partIds[id];
      if (p) p.classList.add("dead");
    });

    if (currentRound >= maxRounds) {
      setTimeout(() => {
        message.textContent = `FIM DE JOGO! ${totalCorrect} ACERTOS EM ${maxRounds} RODADAS!`;
        message.className = "message show success";
        addRankingEntry(totalCorrect, totalWrong);
        endGame();
      }, 1500);
    } else {
      setTimeout(() => {
        currentRound++;
        initGame();
      }, 2000);
    }
  }
}

function endGame() {
  document.querySelectorAll(".key-btn").forEach(b => b.disabled = true);
  restartBtn.classList.add("show");
  stopTimer();
  isGameActive = false;
}

function startGame(difficulty, category) {
  currentDifficulty = difficulty;
  currentCategory = category;
  const settings = difficultySettings[difficulty];
  maxRounds = 5;
  currentRound = 1;
  totalCorrect = 0;
  totalWrong = 0;
  initGame();
}

function getQueryParams() {
  const params = new URLSearchParams(window.location.search);
  return {
    difficulty: params.get('difficulty') || 'easy',
    category: params.get('category') || 'random'
  };
}

function openRules() {
  rulesModal.style.display = 'flex';
}

function closeRules() {
  rulesModal.style.display = 'none';
}

homeBtn.addEventListener('click', function() {
  playSound("click");
  goHome();
});

muteBtn.addEventListener('click', function() {
  playSound("click");
  toggleMute();
});

rulesHeaderBtn.addEventListener('click', function() {
  playSound("click");
  openRules();
});

rulesCloseBtn.addEventListener('click', function() {
  playSound("click");
  closeRules();
});

rulesModal.addEventListener('click', function(e) {
  if (e.target === this) {
    playSound("click");
    closeRules();
  }
});

hintBtn.addEventListener('click', function() {
  playSound("click");
  useHint();
});

restartBtn.addEventListener('click', function() {
  playSound("click");
  
  setTimeout(function() {
    stopLoseSound();
    stopTimer();
    currentRound = 1;
    totalCorrect = 0;
    totalWrong = 0;
    const params = getQueryParams();
    startGame(params.difficulty, params.category);
  }, 300);
});
document.addEventListener("keydown", function(e) {
  if (e.keyCode >= 65 && e.keyCode <= 90 && isGameActive) {
    const letter = e.key.toLowerCase();
    const btn = document.querySelector(`.key-btn[data-letter="${letter}"]`);
    if (btn && !btn.disabled) btn.click();
  }
});

window.addEventListener('resize', function() {
  const c = fireCanvas;
  if (c) { c.width = window.innerWidth; c.height = window.innerHeight; }
});


function updateDifficultyBadge() {
  const badge = document.getElementById('difficultyBadge');
  const diffNames = {
    'easy': 'Fácil',
    'medium': 'Médio',
    'hard': 'Difícil'
  };
  badge.textContent = `${diffNames[currentDifficulty] || currentDifficulty}`;
}


const params = getQueryParams();
loadRanking();
renderRanking();
startGame(params.difficulty, params.category);